// Initialize Lucide icons after DOM content loads
function initializeIcons() {
  if (window.lucide) {
    lucide.createIcons();
  }
}

// Toggle mobile menu visibility
function toggleMobileMenu() {
  const menu = document.getElementById('mobile-menu');
  const icon = document.querySelector('#mobile-menu-btn i');

  if (!menu || !icon) return; // Guard clause for pages without mobile menu

  const isOpen = !menu.classList.contains('hidden');

  if (isOpen) {
    menu.classList.add('hidden');
    icon.setAttribute('data-lucide', 'menu');
  } else {
    menu.classList.remove('hidden');
    icon.setAttribute('data-lucide', 'x');
  }

  initializeIcons(); // Re-render icons after change
}

// Fetch destinations from server and update UI if callback provided
async function loadDestinations(callback) {
  try {
    const response = await fetch('http://localhost:5000/api/destinations');

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const data = await response.json();
    // Update global DESTINATIONS if needed, but for now, use static data

    if (callback && typeof callback === 'function') {
      callback(data);
    }
  } catch (error) {
    console.error('Failed to load destinations:', error);
    // Fallback to static data or show error message
    if (callback && typeof callback === 'function') {
      callback(DESTINATIONS); // Use static data as fallback
    }
  }
}

// =========================
// PAGE-SPECIFIC INITIALIZATION
// =========================

// Login page functionality
function initializeLoginPage() {
  const loginForm = document.getElementById('login-form');
  if (!loginForm) return;

  loginForm.addEventListener('submit', async (e) => {
    e.preventDefault();

    const email = document.getElementById('login-email').value.trim();
    const password = document.getElementById('login-pass').value.trim();

    if (!email || !password) {
      alert('Please enter email and password.');
      return;
    }

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const user = userCredential.user;

      // Redirect based on user role
      if (user.email === 'admin@hiddenpath.com') {
        window.location.href = 'admin.html';
      } else {
        window.location.href = 'home.html'; // or wherever regular users go
      }
    } catch (error) {
      console.error('Login error:', error);
      alert('Login failed: ' + error.message);
    }
  });

  // Password visibility toggle
  const togglePassword = document.getElementById('toggle-password');
  if (togglePassword) {
    togglePassword.addEventListener('click', () => {
      const passwordInput = document.getElementById('login-pass');
      if (passwordInput.type === 'password') {
        passwordInput.type = 'text';
        togglePassword.textContent = 'Hide';
      } else {
        passwordInput.type = 'password';
        togglePassword.textContent = 'Show';
      }
    });
  }
}

