// =========================
// GLOBAL EVENT LISTENERS
// =========================

// DOM Content Loaded - Initialize common functionality
document.addEventListener('DOMContentLoaded', () => {
  // Initialize icons
  initializeIcons();

  // Set up mobile menu toggle if button exists
  const mobileBtn = document.getElementById('mobile-menu-btn');
  if (mobileBtn) {
    mobileBtn.addEventListener('click', toggleMobileMenu);
  }

  // Firebase auth state listener
  onAuthStateChanged(auth, (user) => {
    if (user) {
      // User is signed in
      console.log('User signed in:', user.email);
      // Show logout button if on a page with nav
      showLogoutButton();
      // Redirect from login/register if already logged in
      if (window.location.pathname.includes('login.html') || window.location.pathname.includes('register.html')) {
        window.location.href = 'home.html';
      }
    } else {
      // User is signed out
      console.log('User signed out');
      hideLogoutButton();
      // Redirect to login if on protected page
      if (!window.location.pathname.includes('login.html') && !window.location.pathname.includes('register.html') && !window.location.pathname.includes('about.html')) {
        window.location.href = 'login.html';
      }
    }
  });

  // Page-specific initialization
  if (document.getElementById('login-form')) {
    initializeLoginPage();
  }

  if (document.getElementById('map')) {
    initializeMapPage();
  }

  // Load destinations for pages that need them
  if (window.location.pathname.includes('home.html') || window.location.pathname.includes('places.html')) {
    loadDestinations();
  }

  // Load alerts from Firestore for alerts page
  if (window.location.pathname.includes('alerts.html')) {
    loadAlertsFromFirestore();
  }

  // Initialize Places Filter
  if (window.location.pathname.includes('places.html')) {
    initializePlacesFilter();
  }
});

// =========================
// FIRESTORE FUNCTIONS
// =========================

// Load alerts from Firestore with real-time updates
function loadAlertsFromFirestore() {
  const alertsCollection = collection(db, 'alerts');

  // Use onSnapshot for real-time updates
  onSnapshot(alertsCollection, (snapshot) => {
    const alerts = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    renderAlerts(alerts);
  }, (error) => {
    console.error('Failed to load alerts from Firestore:', error);
    // Fallback to static data if needed, but per user: source of truth is Firestore
    renderAlerts([]);
  });
}

// Render alerts on the page
// Render alerts on the page
function renderAlerts(alerts) {
  const highContainer = document.getElementById('alerts-high');
  const mediumContainer = document.getElementById('alerts-medium');
  const lowContainer = document.getElementById('alerts-low');

  // Check if we are on the alerts page by presence of containers
  if (!highContainer || !mediumContainer || !lowContainer) return;

  // Clear existing content (loaders or placeholders)
  highContainer.innerHTML = '';
  mediumContainer.innerHTML = '';
  lowContainer.innerHTML = '';

  const highAlerts = alerts.filter(a => a.severity === 'high');
  const mediumAlerts = alerts.filter(a => a.severity === 'medium');
  const lowAlerts = alerts.filter(a => a.severity === 'low');

  // Helper to render card
  const createCard = (alert, colorClass, borderColor, icon) => `
      <div class="bg-white p-4 rounded-xl border-l-4 ${borderColor} shadow-sm hover:shadow-md transition-shadow">
        <div class="flex justify-between items-start mb-2">
            <div class="flex items-center gap-2">
              <span class="text-xs font-bold uppercase tracking-wider ${colorClass} bg-stone-100 px-2 py-1 rounded-md">
                  ${alert.type}
              </span>
              ${alert.location ? `<span class="text-xs text-stone-500 font-medium flex items-center gap-1"><i data-lucide="map-pin" class="w-3 h-3"></i>${alert.location}</span>` : ''}
            </div>
            <span class="text-xs text-stone-400">Now</span>
        </div>
        <p class="text-stone-700 font-medium text-sm leading-relaxed">${alert.message}</p>
      </div>
  `;

  // Render High
  if (highAlerts.length > 0) {
    highContainer.innerHTML = highAlerts.map(alert =>
      createCard(alert, 'text-red-600', 'border-red-500', 'siren')
    ).join('');
  } else {
    highContainer.innerHTML = `
        <div class="text-center py-8 opacity-60">
            <i data-lucide="shield-check" class="w-8 h-8 mx-auto mb-2 text-red-300"></i>
            <p class="text-sm text-red-400">No critical alerts currently active.</p>
        </div>`;
  }

  // Render Medium
  if (mediumAlerts.length > 0) {
    mediumContainer.innerHTML = mediumAlerts.map(alert =>
      createCard(alert, 'text-amber-600', 'border-amber-500', 'alert-triangle')
    ).join('');
  } else {
    mediumContainer.innerHTML = `
        <div class="text-center py-8 opacity-60">
            <i data-lucide="check" class="w-8 h-8 mx-auto mb-2 text-amber-300"></i>
            <p class="text-sm text-amber-400">All clear for now.</p>
        </div>`;
  }

  // Render Low
  if (lowAlerts.length > 0) {
    lowContainer.innerHTML = lowAlerts.map(alert =>
      createCard(alert, 'text-emerald-600', 'border-emerald-500', 'info')
    ).join('');
  } else {
    lowContainer.innerHTML = `
        <div class="text-center py-8 opacity-60">
            <i data-lucide="bell-off" class="w-8 h-8 mx-auto mb-2 text-emerald-300"></i>
            <p class="text-sm text-emerald-400">No new notices.</p>
        </div>`;
  }

  initializeIcons();
}

// =========================
// AUTH FUNCTIONS
// =========================

// Show logout button in nav
function showLogoutButton() {
  const nav = document.querySelector('nav');
  if (!nav) return;

  // Check if logout button already exists
  if (document.getElementById('logout-btn')) return;

  const logoutBtn = document.createElement('button');
  logoutBtn.id = 'logout-btn';
  logoutBtn.innerHTML = '<i data-lucide="log-out" class="w-4 h-4"></i> Logout';
  logoutBtn.className = 'flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors';
  logoutBtn.addEventListener('click', handleLogout);

  // Add to nav, perhaps after the logo or in a user section
  const navContainer = nav.querySelector('.flex.items-center.justify-between');
  if (navContainer) {
    navContainer.appendChild(logoutBtn);
  }

  initializeIcons();
}

// Hide logout button
function hideLogoutButton() {
  const logoutBtn = document.getElementById('logout-btn');
  if (logoutBtn) {
    logoutBtn.remove();
  }
}

// Handle logout
async function handleLogout() {
  try {
    await signOut(auth);
    // Redirect handled by onAuthStateChanged
  } catch (error) {
    console.error('Logout error:', error);
    alert('Logout failed: ' + error.message);
  }
}

