// =========================
// PLACES FILTER
// =========================

function initializePlacesFilter() {
  const btnAll = document.getElementById('btn-all');
  const btnHidden = document.getElementById('btn-hidden');
  const cards = document.querySelectorAll('.place-card');

  if (!btnAll || !btnHidden) return;

  function filterPlaces(type) {
    // Update Button Styles
    if (type === 'all') {
      btnAll.classList.replace('bg-white', 'bg-[#4A644A]');
      btnAll.classList.replace('text-[#4A644A]', 'text-white');
      btnAll.classList.remove('border');

      btnHidden.classList.replace('bg-[#4A644A]', 'bg-white');
      btnHidden.classList.replace('text-white', 'text-[#4A644A]');
      btnHidden.classList.add('border');
    } else {
      btnHidden.classList.replace('bg-white', 'bg-[#4A644A]');
      btnHidden.classList.replace('text-[#4A644A]', 'text-white');
      btnHidden.classList.remove('border');

      btnAll.classList.replace('bg-[#4A644A]', 'bg-white');
      btnAll.classList.replace('text-white', 'text-[#4A644A]');
      btnAll.classList.add('border');
    }

    // Filter Cards
    cards.forEach(card => {
      if (type === 'all') {
        card.style.display = 'flex';
        // Add fade in effect
        card.style.opacity = '0';
        setTimeout(() => card.style.opacity = '1', 50);
      } else {
        if (card.dataset.type === 'hidden-gem') {
          card.style.display = 'flex';
          card.style.opacity = '0';
          setTimeout(() => card.style.opacity = '1', 50);
        } else {
          card.style.display = 'none';
        }
      }
    });
  }

  btnAll.addEventListener('click', () => filterPlaces('all'));
  btnHidden.addEventListener('click', () => filterPlaces('hidden'));
}

